INSERT INTO t_sys_help_content (help_id, page_code, title, summary, content, sort_order, help_status) VALUES
('help0000000000000000000000000001', 'sys-user', '如何创建用户', '点击"新增用户"按钮，填写基本信息后提交。', '1. 点击页面右上角"新增用户"按钮\n2. 填写登录账号（不可重复）、用户姓名、初始密码\n3. 选择部门和角色\n4. 点击"确认"完成创建', 1, 'ACTIVE'),
('help0000000000000000000000000002', 'sys-user', '用户状态说明', '用户有启用、锁定、禁用三种状态。', '启用（ACTIVE）：用户可正常登录\n锁定（LOCKED）：连续登录失败 5 次自动锁定，30 分钟后自动解锁\n禁用（DISABLED）：管理员手动禁用，需管理员手动启用', 2, 'ACTIVE'),
('help0000000000000000000000000003', 'sys-role', '角色与权限', '角色决定用户可访问的菜单和功能。', '系统预置管理员角色（不可删除）。\n自定义角色通过"分配权限"按钮配置菜单访问权限。\n一个用户可关联多个角色，权限取并集。', 1, 'ACTIVE'),
('help0000000000000000000000000004', 'sys-menu', '菜单管理说明', '菜单支持三级树形结构。', '一级菜单：顶部导航栏入口\n二级菜单：左侧菜单栏\n三级菜单：页面内功能按钮\n菜单排序值越小越靠前。', 1, 'ACTIVE'),
('help0000000000000000000000000005', 'sys-message', '消息类型说明', '系统支持四种消息类型。', '系统通知：平台维护、升级公告\n业务提醒：业务流程状态变更\n预警消息：接口异常、数据阈值告警\n待办任务：需要用户处理的任务', 1, 'ACTIVE'),
('help0000000000000000000000000006', 'sys-download', '下载任务说明', '大数据量导出采用异步方式处理。', '单次导出超过 1 万条数据时，系统自动创建异步下载任务。\n任务完成后可在此页面下载文件。\n文件保留 7 天，过期后自动清理。', 1, 'ACTIVE');
